+            .field("manager", &self.manager)
+            .field("cleanup_budget", &self.cleanup_budget)
+            .field(
+                "shutdown_done",
+                &self
+                    .shutdown_done
+                    .load(std::sync::atomic::Ordering::Relaxed),
+            )
+            .finish()
+    }
+}
